298.     /// </summary>
299.     /// <param name="input">The date to humanize.</param>
300.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
301.     /// <returns>A human-readable string representing the time difference.</returns>
302.     public virtual string Humanize(DateTime input, DateTime comparedTo)
303.     {
304.         var difference = comparedTo - input;
305.         if (Math.Abs(difference.TotalSeconds) < 2)
306.         {
307.             return "just now";
308.         }
309. 
310.         var isFuture = difference.TotalSeconds < 0;
311.         var absDiff = difference.Duration();
312. 
313.         var result = absDiff.TotalDays switch
314.         {
315.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
316.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
317.             >= 1 => $"{(int)absDiff.TotalDays} days",
318.             _ => absDiff.TotalHours switch
319.             {
320.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
321.                 _ => absDiff.TotalMinutes switch
322.                 {
323.                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
324.                     _ => $"{(int)absDiff.TotalSeconds} seconds"
325.                 }
326.             }
327.         };
