300. public sealed class DefaultDateTimeHumanizeStrategy
301. {
302.     /// <summary>
303.     /// Humanizes a DateTime difference relative to a base date.
304.     /// </summary>
305.     /// <param name="input">The date to humanize.</param>
306.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
307.     /// <returns>A human-readable string representing the time difference.</returns>
308.     public string Humanize(DateTime input, DateTime comparedTo)
309.     {
310.         var difference = comparedTo - input;
311.         if (Math.Abs(difference.TotalSeconds) < 2)
312.         {
313.             return "just now";
314.         }
315. 
316.         var isFuture = difference.TotalSeconds < 0;
317.         var absDiff = difference.Duration();
318. 
319.         var result = absDiff.TotalDays switch
320.         {
321.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
322.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
323.             >= 1 => $"{(int)absDiff.TotalDays} days",
324.             _ => absDiff.TotalHours switch
325.             {
326.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
327.                 _ => absDiff.TotalMinutes switch
328.                 {
329.                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
330.                     _ => $"{(int)absDiff.TotalSeconds} seconds"
331.                 }
332.             }
333.         };
334. 
335.         return isFuture ? $"in {result}" : $"{result} ago";
336.     }
337. }
